items.signature:
VkResult vkUnmapMemory2(
 VkDevice device,
 const VkMemoryUnmapInfo* pMemoryUnmapInfo);

items.example:
VkDevice device = VK_NULL_HANDLE;
VkMemoryUnmapInfo memoryUnmapInfo = {};
memoryUnmapInfo.sType = VK_STRUCTURE_TYPE_MEMORY_UNMAP_INFO;

VkResult result = vkUnmapMemory2(
    device,
    &memoryUnmapInfo
);

if (result == VK_SUCCESS) {
    // تمت العملية بنجاح ويمكن متابعة العمل بعد vkUnmapMemory2
} else {
    // عالج رمز الخطأ أو أعد تهيئة الموارد المطلوبة
}

